    parser.add_argument('-a', '--assignee', type=str, help='Р В Р’В Р вҖҷР’ВӨР В Р’В Р РҺРІРӮВҳР В Р’В Р вҖҷР’В»Р В Р РӢР В Р вҖ°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В РІРӮСҷ Р В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһ Р В Р’В Р РҺРІРӮВҳР В Р РӢР В РЎвҖңР В Р’В Р РҺРІРӮвҖқР В Р’В Р РҺРІРӮСһР В Р’В Р вҖҷР’В»Р В Р’В Р В РІРӮВҰР В Р’В Р РҺРІРӮВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В»Р В Р РӢР В РІРӮв„–')
    parser.add_argument('-b', '--blocks', type=str, help='Р В Р’В Р РҶР вҖҡР’ВҳР В Р’В Р вҖҷР’В»Р В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮВҳ Р В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҶР вҖҡР РӢР В Р РӢР РҶР вҖҡР’ВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В° (Р В Р РӢР РҶР вҖҡР РӢР В Р’В Р вҖҷР’ВөР В Р РӢР В РІРӮСҷР В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В· Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р РҺРІРӮвҖқР В Р РӢР В Р РҸР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҺРІРӮСҡР В Р РӢР В РІРӮв„–)')
    parser.add_argument('-e', '--excel', action='store_true', help='Р В Р’В Р РҶР вҖҡРІвҖһСһР В Р РӢР РҶР вҖҡРІвҖһвҖ“Р В Р’В Р РҺРІРӮвҖңР В Р РӢР В РІРӮСҷР В Р РӢР РҺРІРӮСҡР В Р’В Р вҖҷР’В·Р В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В° Р В Р’В Р В РІРӮВ  Excel')
    parser.add_argument('-v', '--verbose', action='store_true', help='Р В Р’В Р вҖҷР’В Р В Р’В Р вҖҷР’ВөР В Р’В Р вҖҷР’В¶Р В Р’В Р РҺРІРӮВҳР В Р’В Р РҺР’Вҳ Р В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В»Р В Р’В Р вҖҷР’В°Р В Р’В Р СһРІРӮВҳР В Р’В Р РҺРІРӮСңР В Р’В Р РҺРІРӮВҳ')
    parser.add_argument('-vv', '--extra-verbose', action='store_true', help='Р В Р’В Р РҺРЎСҹР В Р’В Р РҺРІРӮСһР В Р’В Р РҺРІРӮСңР В Р’В Р вҖҷР’В°Р В Р’В Р вҖҷР’В·Р В Р РӢР РҶР вҖҡРІвҖһвҖ“Р В Р’В Р В РІРӮВ Р В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР В Р вҖ° ID Р В Р’В Р вҖҷР’В·Р В Р’В Р вҖҷР’В°Р В Р’В Р СһРІРӮВҳР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР РӢ Р В Р’В Р В РІРӮВ Р В Р’В Р РҺРІРӮСһ Р В Р’В Р В РІРӮВ Р В Р РӢР В РЎвҖңР В Р’В Р вҖҷР’ВөР В Р РӢР РҶР вҖҡР’ВҰ Р В Р’В Р РҺРІРӮСһР В Р РӢР РҶР вҖҡРЎв„ўР В Р РӢР РҶР вҖҡР РӢР В Р РӢР РҶР вҖҡР’ВҳР В Р РӢР РҶР вҖҡРЎв„ўР В Р’В Р вҖҷР’В°Р В Р РӢР РҶР вҖҡР’ВҰ')
    args = parser.parse_args()
    
    blocks = None
    if args.blocks:
        blocks = [b.strip() for b in args.blocks.split(',')]
        invalid = [b for b in blocks if b not in REPORT_BLOCKS]
